INSERT INTO `Products` VALUES (48,'Câble de raccordement duplex OS2 monomode LC de 1,5 mètre','Ce câble de raccordement duplex OS2 monomode LC de 1,5 mètre est conçu pour des applications exigeant une grande précision dans la transmission des données sur fibre optique. Fabriqué à partir de matériaux de haute qualité, il garantit une faible perte d\'insertion et une performance stable, ce qui le rend idéal pour les connexions à courte distance dans des environnements professionnels comme les centres de données et les installations réseau.','https://resource.fs.com/mall/products/800x800/88528.main.jpg',1,11640.00,81),(49,'Câble de raccordement duplex OS2 monomode LC de 3 mètres','Ce câble de 3 mètres est conçu pour des environnements nécessitant une connectivité fiable et efficace. Il prend en charge des transmissions à haut débit sur fibre optique monomode, idéal pour les infrastructures réseau d\'entreprise et les interconnexions dans des environnements où la qualité et la durabilité sont essentielles. Avec son design compact et ses connecteurs LC de précision, il répond parfaitement aux besoins des installations modernes.','https://resource.fs.com/mall/products/800x800/40193.main.jpg',1,6569.00,83),(50,'Câble de raccordement duplex OS2 monomode LC de 10 mètres','Ce câble de 10 mètres est parfait pour les installations réseau nécessitant une portée moyenne à longue distance. Construit avec des fibres OS2 monomode de haute qualité, il garantit une faible atténuation et une transmission fiable, même dans les environnements les plus exigeants. Ses connecteurs LC de haute précision assurent une connectivité rapide et sécurisée, le rendant adapté aux réseaux longue distance dans les entreprises et les centres de données.','https://resource.fs.com/mall/products/800x800/40203.main.jpg',1,2064.00,412),(51,'Câble de raccordement duplex OS2 monomode LC de 15 mètres','Avec une longueur de 15 mètres, ce câble est idéal pour les réseaux nécessitant des connexions plus longues tout en maintenant une performance optimale. Conçu pour une utilisation dans des environnements critiques, il garantit une faible perte et une stabilité exceptionnelle. Que ce soit pour des applications télécoms ou des infrastructures réseau avancées, ce câble offre une solution fiable et durable.','https://resource.fs.com/mall/products/800x800/40204.main.jpg',1,2095.00,333),(52,'Câble de raccordement duplex OS2 monomode LC de 20 mètres','Ce câble de raccordement duplex OS2 monomode LC de 20 mètres est une solution idéale pour des applications longue distance. Il assure une transmission stable grâce à ses fibres de haute qualité et ses connecteurs LC parfaitement alignés. Avec sa conception robuste et ses performances constantes, il convient aux besoins des grandes infrastructures réseau, des entreprises, et des installations de télécommunications.','https://resource.fs.com/mall/products/800x800/40205.main.jpg',1,3235.00,376),(53,'Câble de raccordement duplex OS2 monomode LC de 30 mètres','Ce câble de 30 mètres est spécialement conçu pour répondre aux besoins des réseaux longue distance, offrant une performance exceptionnelle avec une faible atténuation. Les connecteurs LC de haute précision assurent une installation facile et une connectivité robuste. Que ce soit pour les centres de données, les réseaux d\'entreprise ou les télécommunications, ce câble garantit une qualité de transmission supérieure sur de longues distances.','https://resource.fs.com/mall/products/800x800/40206.main.jpg',1,4607.00,106),(54,'Câble de raccordement duplex OM3 multimode LC de 1,5 mètre','Ce câble de raccordement duplex OM3 multimode LC de 1,5 mètre est parfait pour des connexions internes à haut débit. Conçu pour des environnements multimodes, il prend en charge des transmissions à 10 Gb/s et au-delà. Grâce à sa longueur compacte, il est idéal pour des installations à proximité des équipements réseau, garantissant une efficacité maximale et une faible perte.','https://resource.fs.com/mall/products/800x800/88537.main.jpg',1,10428.00,427),(55,'Câble de raccordement duplex OM3 multimode LC de 3 mètres','Ce câble multimode OM3 de 3 mètres est une solution optimale pour des réseaux locaux et des environnements multimodes nécessitant une bande passante élevée. Compatible avec des transmissions 10 Gb/s à 40 Gb/s, il est idéal pour les connexions réseau entre équipements au sein des centres de données modernes. Sa robustesse et sa flexibilité garantissent une performance constante.','https://resource.fs.com/mall/products/800x800/41728.main.jpg',1,8675.00,419),(56,'Câble de raccordement duplex OM3 multimode LC de 10 mètres','Ce câble multimode OM3 LC de 10 mètres offre des performances exceptionnelles pour les applications à haut débit dans des environnements professionnels. Conçu pour supporter des connexions rapides et fiables, il est idéal pour les centres de données et les réseaux locaux. La qualité des fibres OM3 garantit une transmission sans interruption et une faible perte.','https://resource.fs.com/mall/products/800x800/41736.main.jpg',1,2976.00,62),(57,'Câble de raccordement duplex OM3 multimode LC de 20 mètres','Avec une longueur de 20 mètres, ce câble multimode OM3 est conçu pour des réseaux intermédiaires nécessitant une connectivité rapide et stable. Compatible avec les normes 10 Gb/s et 40 Gb/s, il offre une transmission fluide, même dans des environnements complexes. Idéal pour les interconnexions au sein des installations modernes.','https://resource.fs.com/mall/products/800x800/41734.main.jpg',1,10474.00,118),(58,'Câble de raccordement duplex OM3 multimode LC de 30 mètres','Ce câble de 30 mètres est spécialement conçu pour des applications multimodes longue distance nécessitant une bande passante élevée. Il supporte des débits de données jusqu\'à 40 Gb/s, ce qui en fait un choix parfait pour les réseaux avancés. Sa construction robuste et ses connecteurs LC assurent une qualité de transmission exceptionnelle.','https://resource.fs.com/mall/products/800x800/41733.main.jpg',1,4218.00,342),(66,'ASUS ROG Strix G16','L’ASUS ROG Strix G16 est un ordinateur portable gaming haute performance, équipé d’un processeur Intel Core i7 ou i9 et d’une carte graphique NVIDIA RTX 4060/4070/4080, garantissant une expérience fluide et immersive. Son écran 16 pouces Full HD ou QHD avec un taux de rafraîchissement élevé offre une réactivité optimale pour le gaming.\r\n\r\nDoté d’un châssis robuste avec un clavier RGB personnalisable, il intègre un système de refroidissement avancé pour des performances stables. Avec jusqu’à 32 Go de RAM DDR5 et un SSD ultra-rapide, il assure des chargements rapides. Sa connectivité complète (USB-C, HDMI 2.1, Wi-Fi 6E) en fait un choix idéal pour les gamers et créateurs exigeants.','https://i.imgur.com/GQV43Ns.png',2,720267.00,49),(67,'HP 15s Core i3','Le HP 15s Core i3 est un ordinateur portable fiable et abordable, idéal pour la bureautique, le multimédia et les études. Équipé d’un processeur Intel Core i3, de 8 Go de RAM et d’un SSD rapide, il assure une utilisation fluide au quotidien.\r\n\r\nSon écran 15,6 pouces Full HD offre un bon confort visuel, tandis que son design fin et léger le rend facilement transportable. Avec une batterie longue durée et la charge rapide, il permet de travailler en toute mobilité. Parfait pour les utilisateurs recherchant un PC efficace et polyvalent à un prix accessible.','https://i.imgur.com/3mPp3mi.png',2,388027.00,45),(68,'HP 250 G8 Core i3','Le HP 250 G8 Core i3 est un ordinateur portable polyvalent conçu pour la bureautique, les études et le travail en entreprise. Équipé d’un processeur Intel Core i3, de 8 Go de RAM et d’un SSD rapide, il assure une bonne réactivité pour les tâches du quotidien.\r\n\r\nSon écran 15,6 pouces Full HD offre un affichage clair et confortable, tandis que son châssis robuste et léger garantit une bonne durabilité et une facilité de transport. Avec une connectivité complète (USB, HDMI, Wi-Fi 6, Ethernet) et une batterie longue durée, il constitue un choix idéal pour les professionnels et étudiants recherchant un PC fiable et abordable.','https://i.imgur.com/M3o9Mez.png',2,1040106.00,15),(69,'HP ProBook 440 G9 Core i3','Le HP ProBook 440 G9 Core i3 est un ordinateur portable professionnel conçu pour allier performance, sécurité et mobilité. Équipé d’un processeur Intel Core i3 de 12ᵉ génération, de 8 Go de RAM et d’un SSD rapide, il offre une excellente fluidité pour la bureautique et le multitâche.\r\n\r\nSon écran 14 pouces Full HD assure un affichage net et précis, tandis que son châssis robuste en aluminium garantit une durabilité optimale. Grâce à ses fonctionnalités de sécurité avancées, sa connectivité complète (USB-C, HDMI, Wi-Fi 6, Bluetooth 5.2) et son autonomie longue durée, le ProBook 440 G9 est un choix idéal pour les professionnels et étudiants en quête d’un PC fiable et performant.','https://i.imgur.com/LrfpEaY.png',2,419775.00,21),(70,'HP Pavilion 14 Core i5','Le HP Pavilion 14 Core i5 est un ordinateur portable élégant et performant, idéal pour la bureautique, le multimédia et le multitâche quotidien. Équipé d’un processeur Intel Core i5 de 12ᵉ génération, de 16 Go de RAM et d’un SSD rapide, il assure une excellente réactivité et une expérience fluide.\r\n\r\nSon écran 14 pouces Full HD offre des couleurs vives et un bon confort visuel, tandis que son châssis fin et léger le rend facile à transporter. Avec une autonomie prolongée, une charge rapide et une connectivité complète (USB-C, HDMI, Wi-Fi 6, Bluetooth 5.2), le HP Pavilion 14 est un excellent choix pour les étudiants et professionnels recherchant un PC fiable et polyvalent.','https://i.imgur.com/3T4Nrr7.png',2,364783.00,34),(71,'HP EliteBook 840 G8 Core i5','Le HP EliteBook 840 G8 Core i5 est un ordinateur portable haut de gamme conçu pour les professionnels exigeants. Équipé d’un processeur Intel Core i5 de 11ᵉ génération, de 16 Go de RAM et d’un SSD ultra-rapide, il offre une performance fluide et sécurisée pour le travail multitâche et les applications professionnelles.\r\n\r\nSon écran 14 pouces Full HD antireflet garantit un confort visuel optimal, tandis que son châssis robuste en aluminium assure durabilité et élégance. Grâce à ses fonctionnalités de sécurité avancées (HP Sure Start, TPM, lecteur d’empreintes), sa connectivité complète (USB-C, Thunderbolt, HDMI, Wi-Fi 6, 4G LTE en option) et son autonomie longue durée, le EliteBook 840 G8 est le choix idéal pour les professionnels en déplacement.','https://i.imgur.com/Z8Y7sTV.png',2,902906.00,10),(72,'HP Spectre x360 13 Core i5','Le HP Spectre x360 13 Core i5 est un ultrabook 2-en-1 haut de gamme, alliant élégance, puissance et polyvalence. Doté d’un processeur Intel Core i5 de 12ᵉ génération, de 16 Go de RAM et d’un SSD ultra-rapide, il offre une fluidité exceptionnelle pour la bureautique avancée, le multimédia et la création de contenu.\r\n\r\nSon écran tactile OLED 13,3 pouces Full HD ou 4K, pivotant à 360°, permet une utilisation en mode tablette pour une flexibilité maximale. Avec son design premium en aluminium, son autonomie longue durée, sa connectivité avancée (USB-C Thunderbolt, Wi-Fi 6E, lecteur d’empreintes digitales) et son stylet inclus, le HP Spectre x360 13 est un choix idéal pour les professionnels et les créatifs recherchant un PC portable puissant et ultra-mobile.','https://i.imgur.com/0ALT4BN.png',2,422169.00,35),(73,'HP Envy x360 15 Core i7','Le HP Envy x360 15 Core i7 est un ordinateur portable 2-en-1 puissant et polyvalent, conçu pour les professionnels, créateurs de contenu et utilisateurs exigeants. Grâce à son processeur Intel Core i7 de 12ᵉ génération, ses 16 Go de RAM et son SSD rapide, il garantit une performance fluide et réactive pour le multitâche, le montage vidéo et le gaming occasionnel.\r\n\r\nSon écran tactile 15,6 pouces Full HD ou 4K, pivotant à 360°, permet de l’utiliser en mode tablette, offrant une flexibilité idéale pour la prise de notes et le dessin avec stylet. Avec son design premium en aluminium, sa connectivité avancée (USB-C Thunderbolt, HDMI, Wi-Fi 6E) et son autonomie longue durée avec charge rapide, le HP Envy x360 15 est parfait pour ceux qui recherchent un PC hybride puissant et élégant.','https://i.imgur.com/BHIhHRD.png',2,845054.00,35),(74,'HP Omen 16 Core i7','Le HP Omen 16 Core i7 est un ordinateur portable gaming puissant, conçu pour offrir des performances optimales aux joueurs et aux créateurs de contenu. Doté d’un processeur Intel Core i7 de 12ᵉ ou 13ᵉ génération, de 16 Go de RAM et d’un SSD ultra-rapide, il garantit une fluidité exceptionnelle même sur les jeux et logiciels les plus exigeants.\r\n\r\nSon écran 16,1 pouces Full HD ou QHD, avec un taux de rafraîchissement jusqu’à 165 Hz, assure une expérience immersive et ultra-réactive. Avec sa carte graphique NVIDIA GeForce RTX 4060 ou 4070, il prend en charge le Ray Tracing et la technologie DLSS, offrant des graphismes ultra-réalistes.\r\n\r\nLe HP Omen 16 est équipé d’un système de refroidissement avancé OMEN Tempest, d’un clavier RGB personnalisable, ainsi que d’une connectivité complète (USB-C, HDMI 2.1, Wi-Fi 6E, Ethernet). Idéal pour les gamers et les professionnels de la création, ce PC gaming performant combine puissance, design robuste et polyvalence.','https://i.imgur.com/8ghvNgf.png',2,406523.00,46),(75,'HP ZBook Firefly 15 Core i7','Le HP ZBook Firefly 15 Core i7 est un ordinateur portable professionnel conçu pour les créateurs de contenu, ingénieurs et professionnels de la productivité. Équipé d’un processeur Intel Core i7 de 12ᵉ génération, de 16 Go de RAM et d’un SSD rapide, il offre une puissance optimale pour les logiciels de conception, de modélisation et de montage vidéo.\r\n\r\nSon écran 15,6 pouces Full HD ou 4K, avec une haute précision colorimétrique, garantit une qualité d’affichage exceptionnelle, idéale pour le graphisme et la CAO. Grâce à sa carte graphique dédiée NVIDIA RTX A1000 ou Intel Iris Xe, il gère efficacement les tâches graphiques avancées.\r\n\r\nAvec son châssis robuste en aluminium, sa sécurité renforcée (TPM, lecteur d’empreintes, HP Sure Start) et sa connectivité complète (USB-C Thunderbolt, HDMI, Wi-Fi 6E, 4G LTE en option), le HP ZBook Firefly 15 est le choix idéal pour les professionnels recherchant un PC mobile puissant et sécurisé.','https://i.imgur.com/MeRyouC.png',2,268442.00,20),(76,'Lenovo IdeaPad 3 Core i3','Le Lenovo IdeaPad 3 Core i3 est un ordinateur portable polyvalent et abordable, idéal pour les étudiants, professionnels et utilisateurs à la recherche d’un PC fiable pour un usage quotidien. Équipé d’un processeur Intel Core i3 de 11ᵉ ou 12ᵉ génération, de 8 Go de RAM et d’un SSD rapide, il assure une bonne fluidité pour la navigation web, la bureautique et le multimédia.\r\n\r\nSon écran 15,6 pouces Full HD antireflet offre un bon confort visuel, tandis que son châssis léger et compact le rend facile à transporter. Avec une autonomie longue durée, une charge rapide et une connectivité complète (USB-C, HDMI, Wi-Fi 6, Bluetooth 5.0), le Lenovo IdeaPad 3 est un choix parfait pour ceux qui recherchent un PC fiable et économique.','https://i.imgur.com/0Wuux3T.png',2,791707.00,20),(77,'Lenovo ThinkBook 14 G2 Core i3','Le Lenovo ThinkBook 14 G2 Core i3 est un ordinateur portable professionnel compact et performant, conçu pour les étudiants, entrepreneurs et travailleurs nomades. Équipé d’un processeur Intel Core i3 de 11ᵉ ou 12ᵉ génération, de 8 Go de RAM et d’un SSD rapide, il offre une excellente fluidité pour la bureautique et le multitâche.\r\n\r\nSon écran 14 pouces Full HD antireflet assure un affichage clair et confortable, tandis que son châssis en aluminium robuste garantit une durabilité accrue. Avec une autonomie longue durée, une charge rapide et une connectivité complète (USB-C, HDMI, Wi-Fi 6, lecteur d’empreintes digitales), le ThinkBook 14 G2 est un excellent choix pour les professionnels et étudiants en quête d’un PC portable fiable et élégant.','https://i.imgur.com/bTj9AaY.png',2,776458.00,17),(78,'Lenovo IdeaPad 5 Core i5','Le Lenovo IdeaPad 5 Core i5 est un ordinateur portable performant et polyvalent, idéal pour la bureautique avancée, le multimédia et le travail à distance. Équipé d’un processeur Intel Core i5 de 12ᵉ génération, de 16 Go de RAM et d’un SSD rapide, il garantit une expérience fluide et réactive, même en multitâche.\r\n\r\nSon écran 15,6 pouces Full HD IPS offre une excellente qualité d’affichage avec des couleurs précises, tandis que son châssis fin et élégant en aluminium assure un design moderne et une bonne portabilité. Avec une batterie longue durée, la charge rapide et une connectivité complète (USB-C, HDMI, Wi-Fi 6, Bluetooth 5.1, lecteur d’empreintes digitales), le Lenovo IdeaPad 5 est un choix idéal pour ceux qui recherchent un PC fiable et performant pour le travail et le divertissement.','https://i.imgur.com/gQpHLwr.png',2,577350.00,14),(79,'Lenovo ThinkPad E14 Core i5','Le Lenovo ThinkPad E14 Core i5 est un ordinateur portable professionnel robuste et performant, conçu pour les travailleurs mobiles et les entreprises. Équipé d’un processeur Intel Core i5 de 12ᵉ génération, de 16 Go de RAM et d’un SSD ultra-rapide, il garantit une excellente réactivité pour la bureautique, la gestion de données et le multitâche avancé.\r\n\r\nSon écran 14 pouces Full HD antireflet assure un affichage clair et confortable, tandis que son châssis en aluminium renforcé respecte les normes de durabilité ThinkPad. Avec une autonomie prolongée, un clavier ergonomique rétroéclairé, des fonctions de sécurité avancées (TPM, lecteur d’empreintes, webcam avec cache de confidentialité) et une connectivité complète (USB-C, HDMI, Wi-Fi 6, Bluetooth 5.2), le ThinkPad E14 est un choix idéal pour les professionnels recherchant fiabilité, puissance et mobilité.','https://i.imgur.com/MNqyQh6.png',2,931528.00,32),(80,'Lenovo Yoga 7i Core i7','Le Lenovo Yoga 7i Core i7 est un ultrabook 2-en-1 premium, conçu pour allier performance, flexibilité et design élégant. Doté d’un processeur Intel Core i7 de 12ᵉ ou 13ᵉ génération, de 16 Go de RAM et d’un SSD ultra-rapide, il garantit une expérience fluide et réactive, idéale pour le travail, la création et le divertissement.\r\n\r\nSon écran tactile 14 ou 16 pouces Full HD ou OLED 2.8K, pivotant à 360°, permet une utilisation en mode tablette, parfaite pour la prise de notes ou le dessin avec un stylet compatible. Avec son châssis en aluminium premium, une autonomie longue durée avec charge rapide, et une connectivité avancée (USB-C Thunderbolt 4, HDMI, Wi-Fi 6E, lecteur d’empreintes digitales), le Yoga 7i est l’ultrabook idéal pour les professionnels et créatifs en quête d’un PC hybride puissant et élégant.','https://i.imgur.com/R7z9xyE.png',2,652896.00,35),(81,'Lenovo Legion 5 Core i7','Le Lenovo Legion 5 Core i7 est un ordinateur portable gaming puissant, conçu pour offrir des performances élevées et une immersion totale. Équipé d’un processeur Intel Core i7 de 12ᵉ ou 13ᵉ génération, de 16 Go ou 32 Go de RAM, et d’un SSD ultra-rapide, il assure une fluidité parfaite pour les jeux et les applications gourmandes.\r\n\r\nSon écran 15,6 ou 16 pouces Full HD ou QHD, avec un taux de rafraîchissement jusqu’à 165 Hz, garantit une réactivité optimale et des couleurs précises. Avec une carte graphique NVIDIA GeForce RTX 4060 ou 4070, il prend en charge le Ray Tracing et la technologie DLSS pour des graphismes ultra-réalistes.\r\n\r\nDoté d’un système de refroidissement avancé Legion Coldfront, d’un clavier RGB personnalisable, et d’une connectivité complète (USB-C, HDMI 2.1, Wi-Fi 6E, Ethernet, Bluetooth 5.2), le Legion 5 est le choix parfait pour les gamers et les créateurs de contenu recherchant puissance, design robuste et polyvalence.','https://i.imgur.com/BvPvxTq.png',2,971278.00,25),(82,'Dell Inspiron 15 3000 Core i3','Un PC portable abordable avec un écran 15,6 pouces, idéal pour la bureautique et les études.','https://i.imgur.com/VGK0Eav.png',2,728211.00,32),(83,'Dell Vostro 14 3400 Core i3','Un ordinateur professionnel compact avec un écran 14 pouces Full HD et une bonne autonomie.','https://i.imgur.com/vOwqGBW.png',2,444521.00,22),(84,'Dell Inspiron 16 Plus Core i5','Un PC multimédia performant avec un écran 16 pouces Full HD+ et un design moderne.','https://i.imgur.com/Nx5fKnM.png',2,442003.00,5),(85,'Dell Latitude 5420 Core i5','Un PC robuste conçu pour les professionnels, avec un écran 14 pouces et une sécurité renforcée.','https://i.imgur.com/2dWauEI.png',2,547369.00,41),(86,'Dell XPS 13 Core i7','Un ultrabook premium avec un écran InfinityEdge 13,4 pouces et un design ultra-fin.','https://i.imgur.com/axHC9hb.png',2,971984.00,9),(87,'Dell Alienware m15 Core i7','Un ordinateur portable gaming avec un écran 15,6 pouces 165Hz et une carte graphique dédiée.','https://i.imgur.com/181UHPN.png',2,891391.00,36),(88,'Apple iPad Pro 12.9\"','L’Apple iPad Pro 12.9” est la tablette la plus puissante d’Apple, conçue pour les professionnels, créateurs et utilisateurs exigeants. Doté de la puce Apple M2, il offre des performances exceptionnelles, permettant de gérer des applications lourdes comme le montage vidéo, la modélisation 3D et le gaming avancé avec une fluidité incomparable.\r\n\r\nSon écran Liquid Retina XDR de 12,9 pouces, avec la technologie mini-LED et ProMotion (120 Hz), offre une luminosité intense, des contrastes profonds et une précision colorimétrique incroyable, idéale pour les graphistes et vidéastes.\r\n\r\nCompatible avec l’Apple Pencil (2ᵉ génération) et le Magic Keyboard, il transforme l’expérience utilisateur en véritable station de travail mobile. Avec iPadOS, la connectivité 5G en option, Face ID, USB-C Thunderbolt et une autonomie longue durée, l’iPad Pro 12.9” est l’outil ultime pour la productivité, la créativité et le divertissement haut de gamme.','https://i.imgur.com/leJ5vnG.png',3,194287.00,49),(89,'Apple iPad Air 10.9\"','Un excellent rapport qualité-prix avec écran Liquid Retina et puce M1.','https://i.imgur.com/xZGStKh.png',3,505192.00,19),(90,'Samsung Galaxy Tab S9 Ultra','La Samsung Galaxy Tab S9 Ultra est une tablette haut de gamme ultra-performante, conçue pour les professionnels, créateurs de contenu et utilisateurs exigeants. Dotée d’un écran AMOLED de 14,6 pouces avec une résolution WQXGA+ et un taux de rafraîchissement de 120 Hz, elle offre une qualité d’affichage exceptionnelle, parfaite pour le streaming, le gaming et la création graphique.\r\n\r\nÉquipée du processeur Snapdragon 8 Gen 2, de 12 Go ou 16 Go de RAM et d’un stockage extensible jusqu’à 1 To, elle assure une puissance inégalée pour le multitâche et les applications gourmandes. Compatible avec le S Pen inclus, elle est idéale pour la prise de notes, le dessin et l’édition photo/vidéo.\r\n\r\nGrâce à Android avec l’interface One UI, Samsung DeX, la 5G en option, une batterie longue durée (11 200 mAh) avec charge rapide et une connectivité complète (USB-C, Wi-Fi 6E, Bluetooth 5.3), la Galaxy Tab S9 Ultra est l’outil parfait pour allier productivité et divertissement sur grand écran.','https://i.imgur.com/QQ4Lfp0.png',3,500077.00,14),(91,'Samsung Galaxy Tab A8 10.5\"','Une tablette abordable avec écran LCD et autonomie longue durée.','https://i.imgur.com/aUZ7M6s.png',3,404729.00,12),(92,'Lenovo Tab P11 Pro Gen 2','Une tablette multimédia avec un écran OLED 11,2 pouces et Snapdragon 870.','https://i.imgur.com/CdCqu7o.png',3,239176.00,13),(93,'Lenovo Yoga Tab 13','Une tablette avec support intégré et écran 2K de 13 pouces.','https://i.imgur.com/3AqUAZg.png',3,351787.00,47),(94,'Microsoft Surface Pro 9','La Microsoft Surface Pro 9 est une tablette hybride haut de gamme, conçue pour offrir la puissance d’un ordinateur portable et la flexibilité d’une tablette. Équipée des processeurs Intel Core i5 ou i7 de 12ᵉ génération ou d’une version ARM avec Microsoft SQ3, elle assure des performances exceptionnelles pour la productivité, la créativité et le multitâche avancé.\r\n\r\nSon écran tactile PixelSense Flow de 13 pouces offre une résolution de 2880 x 1920, un taux de rafraîchissement de 120 Hz et une compatibilité avec le Surface Slim Pen 2, idéal pour la prise de notes et le dessin. Son châssis en aluminium ultra-fin et son pied ajustable permettent une utilisation confortable en mode tablette, PC portable ou studio de création.\r\n\r\nAvec Windows 11, jusqu’à 32 Go de RAM, un SSD jusqu’à 1 To, une autonomie allant jusqu’à 15 heures, et une connectivité complète (USB-C Thunderbolt 4, Wi-Fi 6E, 5G en option sur la version ARM), la Surface Pro 9 est un choix idéal pour les professionnels, étudiants et créateurs cherchant un appareil puissant, léger et ultra-polyvalent.','https://i.imgur.com/ipgxUnj.png',3,381364.00,67),(95,'Microsoft Surface Go 3','Une tablette compacte sous Windows avec un écran de 10,5 pouces.','https://i.imgur.com/PtwQNwH.png',3,329839.00,40),(96,'Xiaomi Pad 6 Pro','Un excellent rapport qualité-prix avec écran 11 pouces 144Hz et Snapdragon 8+ Gen 1.','https://i.imgur.com/HH6w1kI.png',3,284678.00,70),(97,'Huawei MatePad 11 2023','La Huawei MatePad 11 2023 est une tablette polyvalente et performante, idéale pour la bureautique, la créativité et le divertissement. Dotée d’un écran LCD 11 pouces 2.5K (2560 x 1600) avec un taux de rafraîchissement de 120 Hz, elle assure une fluidité optimale et un affichage précis, parfait pour le multimédia et la lecture.\r\n\r\nÉquipée du processeur Qualcomm Snapdragon 865, de 6 Go ou 8 Go de RAM, et d’un stockage jusqu’à 256 Go, elle garantit une performance fluide pour le multitâche et les applications professionnelles. Son système audio à quatre haut-parleurs Harman Kardon offre une expérience sonore immersive.\r\n\r\nAvec HarmonyOS 3.1, une batterie de 7 250 mAh avec charge rapide 22,5W, la compatibilité avec le Huawei M-Pencil 2ᵉ génération et un clavier magnétique, la Huawei MatePad 11 2023 est un excellent choix pour les étudiants, professionnels et amateurs de contenu multimédia.','https://i.imgur.com/yITzXJ6.png',3,290341.00,76),(98,'Apple iPhone 16 Pro Max','L’Apple iPhone 16 Pro Max (prévisionnel) devrait être le smartphone le plus avancé d’Apple, offrant des performances de pointe, un design premium et des innovations technologiques inédites. Il serait équipé de la puce A18 Pro, garantissant une puissance et une efficacité énergétique accrues, parfaites pour le gaming, la photographie et la productivité mobile.\r\n\r\nSon écran OLED ProMotion de 6,9 pouces offrirait une luminosité améliorée et un taux de rafraîchissement adaptatif de 120 Hz, garantissant une expérience fluide et immersive. Côté photo, le nouveau capteur 48 MP avec zoom périscopique améliorerait considérablement la photographie en basse lumière et la capture de détails.\r\n\r\nAvec iOS 18, un châssis en titane plus léger, une autonomie optimisée, une connectivité avancée (USB-C, 5G, Wi-Fi 7) et des fonctionnalités IA inédites, l’iPhone 16 Pro Max s’annonce comme le smartphone ultime pour les utilisateurs exigeants.','https://i.imgur.com/3jXmfOo.png',6,658749.00,145),(99,'Apple iPhone 16 Pro','L’Apple iPhone 16 Pro (prévisionnel) s’annonce comme un smartphone ultra-performant, combinant design premium, puissance et innovations technologiques. Il serait équipé de la puce A18 Pro, offrant des performances accrues et une meilleure efficacité énergétique, idéales pour le multitâche, la photographie et le gaming.\r\n\r\nSon écran OLED ProMotion de 6,3 pouces, avec un taux de rafraîchissement adaptatif de 120 Hz, garantirait une expérience visuelle fluide et immersive. L’appareil photo serait amélioré avec un capteur principal 48 MP et un zoom périscopique avancé, offrant une meilleure qualité en basse lumière et des capacités de zoom améliorées.\r\n\r\nAvec iOS 18, un châssis en titane plus léger, une autonomie optimisée, et une connectivité avancée (USB-C, 5G, Wi-Fi 7), l’iPhone 16 Pro promet d’être un smartphone haut de gamme idéal pour les utilisateurs exigeants.','https://i.imgur.com/H9L9A2S.png',6,890104.00,114),(100,'Apple iPhone 16 Plus','L’Apple iPhone 16 Plus (prévisionnel) devrait être une version grand format de l’iPhone 16, offrant une autonomie améliorée, un écran plus immersif et des performances optimisées. Il serait équipé de la puce A18 Bionic, garantissant une rapidité et une efficacité énergétique accrues pour le multitâche, le gaming et la photographie.\r\n\r\nSon écran OLED de 6,7 pouces avec True Tone et ProMotion (taux de rafraîchissement de 120 Hz) offrirait une expérience visuelle fluide et immersive. Côté photo, il embarquerait un double capteur amélioré de 48 MP, avec des performances optimisées en basse lumière et un mode portrait avancé.\r\n\r\nAvec iOS 18, un châssis plus léger et résistant, une autonomie prolongée, et une connectivité avancée (USB-C, 5G, Wi-Fi 7), l’iPhone 16 Plus s’annoncerait comme un smartphone idéal pour ceux qui recherchent un grand écran et une autonomie exceptionnelle.','https://i.imgur.com/nJalC2U.png',6,833231.00,32),(101,'Apple iPhone 16','L’Apple iPhone 16 (prévisionnel) devrait être le modèle standard de la nouvelle génération d’iPhone, offrant un équilibre parfait entre performance, design et autonomie. Il serait équipé de la puce A18 Bionic, garantissant une fluidité améliorée, une meilleure gestion énergétique et des capacités avancées en IA pour la photographie et le multitâche.\r\n\r\nSon écran OLED de 6,1 pouces, avec True Tone et ProMotion (120 Hz en option), offrirait une expérience visuelle fluide et immersive. Côté photo, un double capteur de 48 MP apporterait une meilleure qualité d’image, notamment en basse lumière et en mode portrait.\r\n\r\nAvec iOS 18, un design plus léger et résistant, une batterie optimisée et une connectivité avancée (USB-C, 5G, Wi-Fi 7), l’iPhone 16 serait un excellent choix pour ceux qui recherchent un smartphone puissant et équilibré, sans compromis sur l’autonomie et la qualité photo.','https://i.imgur.com/YuFY4qe.png',6,870456.00,49),(102,'Apple iPhone 15 Pro Max','L’Apple iPhone 15 Pro Max est le modèle le plus avancé de la gamme iPhone 15, conçu pour offrir des performances de pointe, un design premium et des capacités photo exceptionnelles. Il est équipé de la puce A17 Pro, garantissant une puissance inégalée pour le gaming, la productivité et la photographie.\r\n\r\nSon écran OLED Super Retina XDR de 6,7 pouces, avec ProMotion (120 Hz) et Dynamic Island, offre une expérience visuelle fluide et immersive. L’innovation majeure de ce modèle est son zoom périscopique x5, qui améliore considérablement la photographie à longue distance, en complément du capteur principal 48 MP.\r\n\r\nAvec un châssis en titane plus léger et résistant, une batterie longue durée, une connectivité avancée (USB-C, 5G, Wi-Fi 6E) et iOS 17, l’iPhone 15 Pro Max est le choix ultime pour les utilisateurs exigeants recherchant puissance, design et innovation en photographie.','https://i.imgur.com/lNBt3NX.png',6,489590.00,78),(103,'Apple iPhone 15 Pro','L’Apple iPhone 15 Pro est un smartphone haut de gamme, conçu pour offrir des performances de pointe, un design raffiné et des capacités photo avancées. Il est équipé de la puce A17 Pro, garantissant une fluidité optimale pour le gaming, la photographie et la productivité.\r\n\r\nSon écran OLED Super Retina XDR de 6,1 pouces, avec ProMotion (120 Hz) et Dynamic Island, assure une expérience visuelle immersive et réactive. Son capteur principal de 48 MP capture des images ultra-détaillées, tandis que le téléobjectif x3 améliore les prises de vue à distance.\r\n\r\nAvec un châssis en titane plus léger et résistant, une batterie longue durée, une connectivité avancée (USB-C, 5G, Wi-Fi 6E) et iOS 17, l’iPhone 15 Pro est le choix idéal pour ceux qui recherchent puissance, élégance et innovation en photographie.','https://i.imgur.com/KhC0zh7.png',6,918108.00,79),(104,'Apple iPhone 15 Plus','L’Apple iPhone 15 Plus est un smartphone grand format, offrant une excellente autonomie, un écran immersif et des performances optimisées. Il est équipé de la puce A16 Bionic, garantissant une fluidité exceptionnelle pour le multitâche, le gaming et la photographie.\r\n\r\nSon écran OLED Super Retina XDR de 6,7 pouces, avec Dynamic Island, offre une expérience visuelle immersive. Côté photo, son capteur principal de 48 MP améliore la qualité des images en basse lumière et les détails en mode portrait.\r\n\r\nAvec un design en aluminium et verre coloré, une batterie longue durée, un port USB-C, la connectivité 5G et iOS 17, l’iPhone 15 Plus est un choix idéal pour ceux qui recherchent un grand écran et une autonomie exceptionnelle, sans compromis sur la performance.','https://i.imgur.com/wVq2AaJ.png',6,487753.00,114),(105,'Apple iPhone 15','L’Apple iPhone 15 est un smartphone performant et élégant, combinant puissance, design moderne et innovations en photographie. Il est équipé de la puce A16 Bionic, garantissant une fluidité optimale pour le multitâche, les jeux et la capture photo/vidéo.\r\n\r\nSon écran OLED Super Retina XDR de 6,1 pouces, avec Dynamic Island, offre une expérience immersive et réactive. Son capteur principal de 48 MP, avec un zoom x2 optique, améliore considérablement les prises de vue en basse lumière et en mode portrait.\r\n\r\nAvec un design en aluminium et verre teinté, une autonomie améliorée, un port USB-C, la connectivité 5G et iOS 17, l’iPhone 15 est un excellent choix pour ceux qui recherchent un smartphone équilibré, puissant et durable.','https://i.imgur.com/gscmD8V.png',6,454337.00,112),(106,'Samsung Galaxy S24 Ultra','Le Samsung Galaxy S24 Ultra est un smartphone premium ultra-puissant, conçu pour les utilisateurs exigeants, les créateurs de contenu et les professionnels. Il est équipé du processeur Snapdragon 8 Gen 3 (ou Exynos 2400 selon la région), couplé à 12 Go ou 16 Go de RAM, garantissant une fluidité et une puissance exceptionnelles pour le gaming, le multitâche et la photographie avancée.\r\n\r\nSon écran AMOLED 6,8 pouces QHD+ 120 Hz, avec une luminosité améliorée et une meilleure efficacité énergétique, offre une expérience visuelle immersive. Côté photo, il embarque un capteur principal de 200 MP, un téléobjectif périscopique x5 ou x10, et des algorithmes IA pour des clichés ultra-détaillés, même en basse lumière.\r\n\r\nAvec un châssis en titane ultra-résistant, le S Pen intégré, une batterie longue durée de 5000 mAh avec charge rapide 45W, un port USB-C, la connectivité 5G, Wi-Fi 7 et Android 14 avec One UI 6.1, le Galaxy S24 Ultra est l’un des smartphones les plus avancés du marché, idéal pour la performance et la créativité.','https://i.imgur.com/BZ2k2Z6.png',6,492630.00,149),(107,'Samsung Galaxy S24+','Le Samsung Galaxy S24+ est un smartphone premium puissant et polyvalent, offrant performance, autonomie et qualité d’affichage exceptionnelles. Il est équipé du processeur Snapdragon 8 Gen 3 (ou Exynos 2400 selon la région), accompagné de 12 Go de RAM, garantissant une fluidité optimale pour le multitâche, le gaming et la photographie.\r\n\r\nSon écran AMOLED 6,7 pouces QHD+ 120 Hz, avec une luminosité améliorée et une consommation énergétique optimisée, offre une expérience visuelle immersive. Côté photo, il dispose d’un capteur principal de 50 MP, d’un téléobjectif x3 et d’un ultra-grand-angle 12 MP, permettant des clichés détaillés même en basse lumière.\r\n\r\nAvec un design premium en aluminium et verre Gorilla Glass Victus 2, une batterie de 4900 mAh avec charge rapide 45W, un port USB-C, la connectivité 5G, Wi-Fi 7, et Android 14 avec One UI 6.1, le Galaxy S24+ est un choix idéal pour ceux qui recherchent un smartphone puissant, autonome et élégant.','https://i.imgur.com/sMSCDie.png',6,720948.00,94),(108,'Samsung Galaxy S24','Le Samsung Galaxy S24 est un smartphone haut de gamme compact et performant, conçu pour offrir une expérience fluide et immersive. Il est équipé du processeur Snapdragon 8 Gen 3 (ou Exynos 2400 selon la région), associé à 8 Go de RAM, garantissant une excellente réactivité pour le multitâche, le gaming et la photographie.\r\n\r\nSon écran AMOLED 6,2 pouces Full HD+ 120 Hz, avec une luminosité améliorée et un affichage ultra-fluide, assure une expérience visuelle premium. Côté photo, il intègre un capteur principal de 50 MP, un téléobjectif x3 et un ultra-grand-angle 12 MP, permettant des clichés détaillés et une excellente gestion des conditions de faible luminosité grâce à l’IA avancée.\r\n\r\nAvec un design en aluminium renforcé, une batterie de 4000 mAh avec charge rapide 25W, un port USB-C, la connectivité 5G, Wi-Fi 7 et Android 14 avec One UI 6.1, le Galaxy S24 est un smartphone compact et puissant, parfait pour une utilisation quotidienne fluide et efficace.','https://i.imgur.com/7X0Bofu.png',6,714344.00,126),(109,'Samsung Galaxy Z Fold 5','Le Samsung Galaxy Z Fold 5 est un smartphone pliable ultra-premium, conçu pour offrir une expérience multitâche et immersive inégalée. Il est équipé du processeur Snapdragon 8 Gen 2 for Galaxy, associé à 12 Go de RAM et jusqu’à 1 To de stockage, garantissant une fluidité exceptionnelle pour le gaming, la productivité et le multitâche avancé.\r\n\r\nSon écran principal AMOLED de 7,6 pouces QXGA+ 120 Hz, associé à un écran externe AMOLED de 6,2 pouces HD+ 120 Hz, offre une expérience immersive et fluide. Grâce à Android 13 avec One UI 5.1.1, il permet d’exécuter plusieurs applications simultanément en mode multifenêtre et est optimisé pour Samsung DeX et le S Pen.\r\n\r\nAvec un châssis plus fin et léger, une charnière améliorée sans espace visible, une batterie de 4400 mAh avec charge rapide 25W, un port USB-C, la connectivité 5G, Wi-Fi 6E et Bluetooth 5.3, le Galaxy Z Fold 5 est le choix ultime pour les professionnels et les amateurs de technologie recherchant un appareil hybride entre smartphone et tablette.','https://i.imgur.com/0iPYRUt.png',6,934001.00,77),(110,'Samsung Galaxy Z Flip 5','Écran pliable AMOLED 6,7\", Snapdragon 8 Gen 2.','https://i.imgur.com/CSnPiDr.png',6,366939.00,23),(111,'LG OLED G3 65\"','Le LG OLED G3 65” est un téléviseur OLED haut de gamme, conçu pour offrir une expérience visuelle exceptionnelle avec des couleurs vives, des noirs profonds et un contraste infini. Équipé de la technologie OLED evo, il propose un écran de 65 pouces offrant une résolution 4K avec une luminosité améliorée par rapport aux modèles précédents, garantissant des images plus brillantes sans sacrifier la qualité des noirs.\r\n\r\nLe processeur α9 Gen 6 AI optimise l’image et le son en temps réel, offrant une qualité d’image immersive et réaliste. Le téléviseur est également compatible avec les technologies Dolby Vision IQ et Dolby Atmos, pour un son surround et une qualité d’image cinématographique.\r\n\r\nAvec des fonctionnalités intelligentes comme webOS, l’accès à des services de streaming (Netflix, Disney+, Prime Video, etc.) et la prise en charge des commandes vocales, le LG OLED G3 65” est le téléviseur idéal pour les cinéphiles et les passionnés de gaming, grâce à des ports HDMI 2.1, un taux de rafraîchissement de 120 Hz et un mode gaming optimisé.','https://i.imgur.com/RkaDjnM.png',4,399376.00,19),(112,'LG QNED85 75\"','Le LG QNED85 75” est un téléviseur QNED haut de gamme, conçu pour offrir une expérience visuelle exceptionnelle avec un excellent rapport qualité-prix. Équipé de la technologie QNED (Quantum NanoCell) avec un rétroéclairage mini-LED, il combine les avantages des LED, NanoCell et Quantum Dot, offrant des couleurs plus riches, un meilleur contraste et des noirs plus profonds pour des images éclatantes.\r\n\r\nSon écran de 75 pouces avec une résolution 4K garantit une expérience visuelle immersive, idéale pour les films, les séries et le sport. Le téléviseur est propulsé par le processeur α7 Gen 5 AI, qui optimise en temps réel l’image et le son pour un rendu plus précis.\r\n\r\nLe LG QNED85 75” est également compatible avec Dolby Vision IQ et Dolby Atmos, offrant des images et un son de qualité cinématographique. Il dispose de webOS, offrant un accès facile aux services de streaming comme Netflix, Disney+ et Prime Video. Avec ses ports HDMI 2.1, son taux de rafraîchissement de 120 Hz et son mode gaming optimisé, c’est un excellent choix pour les gamers et les amateurs de contenu haute définition.','https://i.imgur.com/rWB0Wqf.png',4,723807.00,21),(113,'Samsung QN90C 65\"','Le Samsung QN90C 65” est un téléviseur Neo QLED haut de gamme, offrant une qualité d’image exceptionnelle grâce à la technologie Quantum Mini LED qui permet un contrôle de rétroéclairage extrêmement précis pour des noirs profonds et des couleurs vives. Son écran 65 pouces avec une résolution 4K et un taux de rafraîchissement de 120 Hz assure une fluidité parfaite, idéale pour les films, les séries et les jeux vidéo.\r\n\r\nLe téléviseur est propulsé par le processeur Neo Quantum 4K de Samsung, qui utilise l’intelligence artificielle pour optimiser l’image et le son en temps réel, offrant ainsi une expérience visuelle immersive avec des détails fins et une netteté accrue.\r\n\r\nAvec la prise en charge de Dolby Vision, HDR10+ et un son Dolby Atmos pour un son surround riche et clair, le Samsung QN90C 65” vous offre une expérience cinématographique à domicile. Son système d’exploitation Tizen vous permet d’accéder facilement aux services de streaming, tandis que la connectivité HDMI 2.1, le mode gaming et la compatibilité avec les consoles de dernière génération (PS5, Xbox Series X) en font un choix idéal pour les gamers.','https://i.imgur.com/KM0EH7m.png',4,557957.00,6),(114,'Samsung The Frame 55\"','Le Samsung The Frame 55” est un téléviseur 4K élégant conçu pour se fondre dans votre décoration intérieure. Lorsqu’il n’est pas utilisé, il se transforme en œuvre d’art grâce à son mode Art qui affiche des tableaux et photos de votre choix.\r\n\r\nDoté de la technologie QLED, il offre des couleurs vives et des noirs profonds pour une qualité d’image impressionnante. Son écran de 55 pouces assure une expérience visuelle immersive, et il est équipé du processeur Quantum 4K pour améliorer l’image en temps réel.\r\n\r\nAvec son design slim, il se fixe facilement au mur, créant une intégration parfaite dans votre espace. Le Samsung The Frame 55” est également compatible avec les services de streaming et dispose de connectivité Wi-Fi pour un accès facile à vos contenus préférés.','https://i.imgur.com/61lskPN.png',4,486922.00,10),(115,'Hisense U8K 65\"','Le Hisense U8K 65” est un téléviseur ULED 4K de 65 pouces offrant une qualité d’image impressionnante grâce à sa technologie Quantum Dot et un rétroéclairage mini-LED, garantissant des couleurs vives et des noirs profonds. Son écran 4K avec un taux de rafraîchissement de 120 Hz assure une expérience fluide pour le gaming et les films.\r\n\r\nLe téléviseur est équipé du processeur AI 4K qui optimise en temps réel l’image et le son pour offrir des performances exceptionnelles. Avec la prise en charge de HDR10+ et Dolby Vision, il propose des images ultra-réalistes. Le son Dolby Atmos garantit une expérience audio immersive.\r\n\r\nAvec des ports HDMI 2.1, Google TV pour un accès facile aux services de streaming, et une connectivité complète, le Hisense U8K 65” est un excellent choix pour les amateurs de divertissement et les gamers.','https://i.imgur.com/4g4nnjX.png',4,629902.00,27),(116,'Hisense A6K 55\"','Le Hisense A6K 55” est un téléviseur LED 4K de 55 pouces, offrant un excellent rapport qualité/prix pour les utilisateurs recherchant un bon téléviseur pour le divertissement quotidien. Son écran 4K UHD garantit une qualité d’image nette et détaillée, idéale pour les films, les séries et les jeux.\r\n\r\nGrâce à la technologie HDR, il améliore la luminosité et les couleurs pour des images plus dynamiques. Le son DTS Virtual:X offre une expérience audio immersive, et avec la connectivité Smart TV, vous avez un accès facile à des services de streaming comme Netflix et YouTube.\r\n\r\nLe Hisense A6K 55” est également équipé de ports HDMI et d’une interface Android TV, permettant une navigation fluide et un contrôle facile via des applications ou l’assistant vocal Google. Un excellent choix pour un téléviseur accessible et performant.','https://i.imgur.com/pWlyfdZ.png',4,385850.00,26),(117,'TCL C845 65\"',' Le TCL C845 65” est un téléviseur QLED 4K de 65 pouces, offrant une qualité d’image exceptionnelle grâce à sa technologie Mini-LED, qui garantit des noirs profonds et des couleurs éclatantes. Son écran 4K avec un taux de rafraîchissement de 120 Hz assure une expérience visuelle fluide, idéale pour les films, les séries et les jeux.\r\n\r\nLe téléviseur prend en charge HDR10+ et Dolby Vision, offrant des images ultra-réalistes avec un contraste et des couleurs améliorés. Le son Dolby Atmos fournit une expérience audio immersive.\r\n\r\nAvec sa connectivité Smart TV sous Google TV, l’accès aux services de streaming comme Netflix et YouTube est facile. Le TCL C845 65” est également compatible avec le contrôle vocal via Google Assistant, offrant une utilisation pratique et fluide. C’est un excellent choix pour ceux qui recherchent un téléviseur performant à un prix compétitif.','https://i.imgur.com/317sZra.png',4,462031.00,19),(118,'TCL P735 55\"','Le TCL P735 55” est un téléviseur LED 4K de 55 pouces, offrant une qualité d’image nette et claire grâce à sa résolution 4K UHD et la technologie HDR10+, qui améliore la luminosité, le contraste et les couleurs pour des visuels plus dynamiques.\r\n\r\nAvec son écran 55 pouces, il est parfait pour une expérience immersive, que ce soit pour regarder des films, des séries ou jouer à des jeux vidéo. Le son Dolby Audio assure une expérience audio riche, tandis que la connectivité Smart TV avec Google TV vous permet d’accéder facilement à des services de streaming tels que Netflix, YouTube, et plus encore.\r\n\r\nLe TCL P735 55” dispose également de Google Assistant intégré, vous permettant de contrôler votre téléviseur par la voix et d’explorer facilement des applications et des contenus. Un excellent choix pour ceux qui recherchent un téléviseur 4K abordable et performant.','https://i.imgur.com/MqEA5SR.png',4,505954.00,26),(119,'HP LaserJet Pro MFP M428fdw','Le HP LaserJet Pro MFP M428fdw est une imprimante multifonction monochrome, idéale pour les petites et moyennes entreprises ou pour un usage professionnel à domicile. Elle offre des fonctionnalités d’impression, de numérisation, de copie et de télécopie, permettant de gérer facilement les tâches de bureau.\r\n\r\nAvec une vitesse d’impression de 40 pages par minute et une résolution de 1200 x 1200 ppp, elle garantit des documents nets et professionnels. Sa connectivité sans fil via Wi-Fi, Ethernet et la possibilité d’imprimer directement depuis des appareils mobiles via Apple AirPrint ou Google Cloud Print rend l’utilisation encore plus flexible.\r\n\r\nLe HP LaserJet Pro MFP M428fdw est également doté d’un écran tactile couleur de 2,7 pouces, facilitant la navigation et l’accès aux fonctions, ainsi que de fonctionnalités de sécurité avancées pour protéger vos informations sensibles. Il est également conçu pour être écoénergétique, avec une gestion automatique de l’alimentation. C’est une solution idéale pour les entreprises qui ont besoin de productivité, de fiabilité et d’efficacité.','https://i.imgur.com/hAT6xML.png',5,163709.00,16),(120,'HP DeskJet 3755','La HP DeskJet 3755 est une imprimante multifonction compacte idéale pour un usage domestique ou personnel. Elle permet d’imprimer, de numériser et de copier des documents avec une résolution d’impression allant jusqu’à 4800 x 1200 ppp.\r\n\r\nAvec une connectivité sans fil (Wi-Fi), elle permet d’imprimer facilement depuis des appareils mobiles via Apple AirPrint ou HP ePrint. Son design compact permet de l’installer facilement dans des espaces réduits. Elle est économique et parfaite pour les petits besoins d’impression à la maison.','https://i.imgur.com/etT0Tdh.png',5,172091.00,22),(121,'Canon PIXMA G7020','La Canon PIXMA G7020 est une imprimante multifonction à jet d’encre, idéale pour les petites entreprises ou les bureaux à domicile. Elle offre des fonctionnalités d’impression, numérisation, copie et télécopie, avec une capacité d’impression élevée grâce à ses réservoirs d’encre rechargeables.\r\n\r\nElle offre une impression sans fil, compatible avec AirPrint, Google Cloud Print et l’impression mobile via l’application Canon PRINT. Avec une vitesse d’impression allant jusqu’à 13 ipm en noir et 6 ipm en couleur, elle est également économe en encre, offrant jusqu’à 6000 pages en noir et 7000 pages en couleur avec un seul remplissage.\r\n\r\nLe Canon PIXMA G7020 est un excellent choix pour ceux qui ont des besoins d’impression à volume élevé et recherchent une solution fiable, économique et performante.','https://i.imgur.com/2gBJfZj.png',5,146346.00,38),(122,'Canon imageCLASS MF743Cdw','Imprimante laser couleur multifonction, Wi-Fi, écran tactile.','https://i.imgur.com/HRMQIa4.png',5,181769.00,25),(123,'Lexmark MB3442adw','Le Lexmark MB3442adw est une imprimante multifonction monochrome conçue pour les bureaux de petite à moyenne taille. Elle offre des fonctionnalités d’impression, de numérisation, de copie et de télécopie, avec une vitesse d’impression de 40 pages par minute, garantissant une productivité élevée.\r\n\r\nL’imprimante dispose d’une résolution d’impression de 1200 x 1200 ppp pour des documents nets et professionnels. Avec des connectivités sans fil (Wi-Fi, Ethernet) et la possibilité d’imprimer via Apple AirPrint ou Google Cloud Print, elle permet une impression mobile pratique.\r\n\r\nLe Lexmark MB3442adw dispose également d’un écran tactile couleur de 2,8 pouces pour une utilisation simple et d’une batterie longue durée, idéale pour les environnements à volume élevé. C’est une solution fiable et économique pour les besoins bureautiques quotidiens.','https://i.imgur.com/4u0lAUl.png',5,186503.00,10),(124,'Lexmark CX331adwe','Le Lexmark CX331adwe est une imprimante multifonction couleur conçue pour les petites et moyennes entreprises. Elle offre des fonctionnalités d’impression, de numérisation, de copie et de télécopie, avec une vitesse d’impression de 22 pages par minute en couleur et en noir et blanc.\r\n\r\nAvec une résolution d’impression de 1200 x 1200 ppp, elle garantit des documents de qualité professionnelle avec des couleurs vives et des détails nets. La connectivité sans fil (Wi-Fi, Ethernet) permet une impression mobile pratique via Apple AirPrint, Google Cloud Print et Android.\r\n\r\nL’écran tactile couleur de 2,8 pouces facilite la navigation et l’accès aux fonctionnalités. Avec ses capacités d’impression recto-verso automatique, le Lexmark CX331adwe est une solution fiable, rapide et économique, idéale pour les bureaux à la recherche de performances de haute qualité.','https://i.imgur.com/pzGr3OK.png',5,107629.00,35);
